const cleanArg = (v) => { const t = String(v == null ? '' : v).trim(); return /^\{[a-zA-Z0-9_]+\}$/.test(t) ? '' : t; };
const q = cleanArg(arg0);
const vRaw = cleanArg(arg1).toLowerCase();
const tbm = { news: 'nws', books: 'bks' }[vRaw] || '';
const params = new URLSearchParams({ q });
if (tbm) params.set('tbm', tbm);
const target = 'https://www.google.com/search?' + params.toString();
setTimeout(() => window.location.assign(target), 0);
return { redirected: true, target, vertical: vRaw || 'web' };

const norm=(s)=>(s||'').replace(/\u00a0/g,' ').replace(/\s+/g,' ').trim();
const timeRe=/^(\d+\s+(minute|hour|day|week|month|year)s?\s+ago|yesterday|today|\d{1,2}\s+\w+\s+\d{4}|\w+\s+\d{1,2},\s*\d{4})$/i;
const looksLikeAge=(t)=>!!t&&t.length<40&&timeRe.test(t);
const pickAge=(card)=>{const spans=Array.from(card.querySelectorAll('span'));for(const s of spans){const t=norm(s.textContent);if(looksLikeAge(t))return t;}return null;};
const pickSource=(card,titleEl)=>{const spans=Array.from(card.querySelectorAll('span'));for(const s of spans){if(titleEl&&!(s.compareDocumentPosition(titleEl)&Node.DOCUMENT_POSITION_FOLLOWING))continue;const t=norm(s.textContent);if(!t||t==='.'||t.length>80)continue;if(looksLikeAge(t))continue;return t;}return null;};
const newsCards=Array.from(document.querySelectorAll('#search .WCv1we, #rso .WCv1we'));
if(newsCards.length>0){return newsCards.map(c=>{const a=c.querySelector('a[href]');const href=a?a.href:null;const titleEl=c.querySelector('.MBeuO, .n0jPhd');const title=titleEl?norm(titleEl.textContent):(a?norm(a.textContent).split('\n')[0]:null);const snipEl=c.querySelector('.UqSP2b, .GI74Re, .HSSq5c');const snippet=snipEl?norm(snipEl.textContent):null;return{title,url:href,snippet,source:pickSource(c,titleEl),age:pickAge(c)};}).filter(r=>r.title&&r.url);}
const cards=Array.from(document.querySelectorAll('#search .MjjYud, #rso .MjjYud, #search .SoaBEf'));
return cards.map(c=>{const h=c.querySelector('h3, .MBeuO');if(!h)return null;const a=c.querySelector('a[href]');if(!a)return null;const snipEl=c.querySelector('.VwiC3b, [data-content-feature], .yXK7lf, .UqSP2b, .HSSq5c, .GI74Re');return{title:norm(h.textContent),url:a.href,snippet:snipEl?norm(snipEl.textContent):null,source:null,age:null};}).filter(Boolean);
